private void xrTableCell40_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

// Get values from the data source
decimal femaleBalance = Convert.ToDecimal(GetCurrentColumnValue("FemaleBalance") ?? 0);
decimal maleBalance = Convert.ToDecimal(GetCurrentColumnValue("MaleBalance") ?? 0);

if (femaleBalance > 0)
{
    // Calculate: (MaleBalance / FemaleBalance) * 100
    decimal result = (maleBalance / femaleBalance) * 100.0m;
    cell.Text = result.ToString("N2"); // Formats to 2 decimal places
}
else
{
    cell.Text = "0.00";
}

sumOfFemalesReport += femaleBalance ;
sumOfMalesReport  += maleBalance ;
}


private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
   decimal femaleBalance = Convert.ToDecimal(GetCurrentColumnValue("FemaleBalance") ?? 0);
    decimal maleBalance = Convert.ToDecimal(GetCurrentColumnValue("MaleBalance") ?? 0);

    sumOfFemales += femaleBalance;
    sumOfMales += maleBalance;

    decimal femalePlaced = Convert.ToDecimal(GetCurrentColumnValue("FemalePlaced") ?? 0);
    decimal femaleMort = Convert.ToDecimal(GetCurrentColumnValue("FemaleMort") ?? 0);

    if (femalePlaced > 0)
    {
        // Calculate percentage for this record
        decimal percentage = (femaleMort / femalePlaced) * 100.0m;

        // Add to sum and increment counter
        sumOfPercentages += percentage;
        recordCount++;
    }

    decimal femaleCulls = Convert.ToDecimal(GetCurrentColumnValue("FemaleCulls") ?? 0);

    if (femalePlaced > 0)
    {
        // Calculate cull percentage for this record
        decimal cullPercentage = (femaleCulls / femalePlaced) * 100.0m;

        // Add to sum and increment counter
        sumOfCullPercentages += cullPercentage;
        cullRecordCount++;
    }

    decimal malePlaced = Convert.ToDecimal(GetCurrentColumnValue("MalePlaced") ?? 0);
    decimal maleMort = Convert.ToDecimal(GetCurrentColumnValue("MaleMort") ?? 0);

    if (malePlaced > 0)
    {
        // Calculate mortality percentage for this record
        decimal maleMortPercentage = (maleMort / malePlaced) * 100.0m;

        // Add to sum and increment counter
        sumOfMaleMortPercentages += maleMortPercentage;
        maleMortRecordCount++;
    }


     decimal maleCulls = Convert.ToDecimal(GetCurrentColumnValue("MaleCulls") ?? 0);

    if (malePlaced > 0)
    {
        // Calculate cull percentage for this record
        decimal maleCullPercentage = (maleCulls / malePlaced) * 100.0m;

        // Add to sum and increment counter
        sumOfMaleCullPercentages += maleCullPercentage;
        maleCullRecordCount++;
    }




    if (femalePlaced > 0)
    {
        // Calculate {@FemaleDepl} = FemaleMort + FemaleCulls
        decimal femaleDepl = femaleMort + femaleCulls;

        // Calculate depletion percentage for this record
        decimal femaleDeplPercentage = (femaleDepl / femalePlaced) * 100.0m;

        // Add to sum and increment counter
        sumOfFemaleDeplPercentages += femaleDeplPercentage;
        femaleDeplRecordCount++;
    }


    decimal cummFemaleMort = Convert.ToDecimal(GetCurrentColumnValue("CummFemaleMort") ?? 0);
    decimal cummFemalCulls = Convert.ToDecimal(GetCurrentColumnValue("CummFemalCulls") ?? 0);
    decimal cumFemaleCond = Convert.ToDecimal(GetCurrentColumnValue("CumFemaleCond") ?? 0);

    if (femalePlaced > 0)
    {
        // Calculate total cumulative female depletion
        decimal totalCumFemaleDepl = cummFemaleMort + cummFemalCulls + cumFemaleCond;

        // Calculate cumulative depletion percentage for this record
        decimal cumFemaleDeplPercentage = (totalCumFemaleDepl / femalePlaced) * 100.0m;

        // Add to sum and increment counter
        sumOfCumFemaleDeplPercentages += cumFemaleDeplPercentage;
        cumFemaleDeplRecordCount++;
    }

    decimal cummMaleMort = Convert.ToDecimal(GetCurrentColumnValue("CummMaleMort") ?? 0);
    decimal cummMaleCulls = Convert.ToDecimal(GetCurrentColumnValue("CummMaleCulls") ?? 0);
    decimal cumMaleCond = Convert.ToDecimal(GetCurrentColumnValue("CumMaleCond") ?? 0);

    if (malePlaced > 0)
    {
        // Calculate total cumulative male depletion
        decimal totalCumMaleDepl = cummMaleMort + cummMaleCulls + cumMaleCond;

        // Calculate cumulative depletion percentage for this record
        decimal cumMaleDeplPercentage = (totalCumMaleDepl / malePlaced) * 100.0m;

        // Add to sum and increment counter
        sumOfCumMaleDeplPercentages += cumMaleDeplPercentage;
        cumMaleDeplRecordCount++;
    }
        // Get values from the data source
    decimal weekStartFemales = Convert.ToDecimal(GetCurrentColumnValue("WeekStartFemales") ?? 0);
    decimal nestedEggs = Convert.ToDecimal(GetCurrentColumnValue("NestedEggs") ?? 0);
    decimal floorEggs = Convert.ToDecimal(GetCurrentColumnValue("FloorEggs") ?? 0);
    decimal pol = Convert.ToDecimal(GetCurrentColumnValue("POL") ?? 0);
    // Get Days parameter
    decimal days = 0;
    if (Parameters["Days"] != null)
    {
        days = Convert.ToDecimal(Parameters["Days"].Value);
    }

    // Calculate total eggs produced
    decimal eggsProd = nestedEggs + floorEggs;

    // Calculate percentage for this record if conditions are met
    if (weekStartFemales > 0 && days > 0)
    {
        decimal percentage = ((eggsProd / days) / weekStartFemales) * 100.0m;

        // Add to sum and increment counter
        sumHenDayPercent += percentage;
        henDayRecordCount++;
    }

     // Apply conditions: POL > 0, Days > 0
    if (pol > 0 && days > 0)
    {
        decimal dailyEggsPerHen = (eggsProd / days) / pol;

        // Only include if dailyEggsPerHen <= 100
        if (dailyEggsPerHen <= 100.0m)
        {
            decimal henDayPercent = dailyEggsPerHen * 100.0m;

            // Add to sum and increment counter
            sumHenDayProd += henDayPercent;
            henDayCount++;
        }

        decimal deformityEggs = Convert.ToDecimal(GetCurrentColumnValue("DeformityEggs") ?? 0);

        decimal deformeEggs = deformityEggs;

        // Accumulate per Site
        sumEggsProdSite += eggsProd;
        sumDeformeEggsSite += deformeEggs;
  }

     // Accumulate totals
    totalEggsProd += eggsProd;
    totalFloorEggs += floorEggs;

    decimal hatchingEggs = Convert.ToDecimal(GetCurrentColumnValue("HatchingEggs") ?? 0);
    decimal hatchingFloorG_B = Convert.ToDecimal(GetCurrentColumnValue("HatchingFloorG_B") ?? 0);
    decimal hatchingFloorG_A = Convert.ToDecimal(GetCurrentColumnValue("HatchingFloorG_A") ?? 0);
    totalEggsProd += nestedEggs + floorEggs;


    // Accumulate {@HatchingFloorEggs} components
    totalHatchingFloorG_B += hatchingFloorG_B;
    totalHatchingFloorG_A += hatchingFloorG_A;

    // Accumulate {@HatchsEggs}
    totalHatchingEggs += hatchingEggs;

    decimal cummChicks1 = Convert.ToDecimal(GetCurrentColumnValue("CummChicks1") ?? 0);
    decimal cummCulls1 = Convert.ToDecimal(GetCurrentColumnValue("CummCulls1") ?? 0);
    decimal cummDeads1 = Convert.ToDecimal(GetCurrentColumnValue("CummDeads1") ?? 0);
    decimal estHatchEggs = Convert.ToDecimal(GetCurrentColumnValue("EstHatchEggs") ?? 0);
    decimal cummSettedEggs1 = Convert.ToDecimal(GetCurrentColumnValue("CummSettedEggs1") ?? 0);

    // Calculate value for this record
    if (femaleBalance != 0 && pol > 0)
    {
        decimal value = (cummChicks1 + cummCulls1 + cummDeads1) / pol;

        // Add to sum and increment counter
        sumOfChicksPerPol += value;
        chicksPerPolCount++;
    }

     // Calculate {@ActCumHatchFarmWise}
    decimal actCumHatchFarmWise = 0;
    decimal totalChicks  = 0;
    totalChicks   = cummChicks1 + cummCulls1 + cummDeads1;
    if (cummSettedEggs1 != 0)
    {
        actCumHatchFarmWise = (totalChicks / cummSettedEggs1) * 100.0m;
    }

    // Calculate value for this record
    if (femaleBalance != 0 && pol > 0)
    {
        decimal currentValue = ((estHatchEggs * actCumHatchFarmWise) / 100.0m) / pol;

        // Add to group totals
        sumEstHatchPerPolGroup += currentValue;
        countEstHatchPerPolGroup++;
    }


     decimal cumChicksHenHoused = Convert.ToDecimal(GetCurrentColumnValue("CumChicksHenHoused") ?? 0);

    // Accumulate only when FemaleBalance is not zero
    if (femaleBalance != 0)
    {
        sumCumChicksHenHoused += cumChicksHenHoused;
        countCumChicksHenHoused++;
    }


   }

