decimal eggsProd = nestedEggs + floorEggs;

// Calculate the value (EggsProd / Days / POL)
decimal value = 0;
if (days > 0 && pol > 0)
{
    value = (eggsProd / days) / pol;
}

// Apply the condition
if (pol > 0 && days > 0 && value <= 100.0m)
{
    decimal result = value * 100.0m;
    cell.Text = result.ToString("N2");
}
else
{
    cell.Text = "0.00";
}
 // Apply conditions: POL > 0, Days > 0
    if (pol > 0 && days > 0)
    {
