    if (totalEggsProdReport > 0 && totalFloorEggsReport > 0)
    {
        decimal result = (totalFloorEggsReport / totalEggsProdReport ) * 100.0m;
        cell.Text = result.ToString("N2") ;
    }
    else
    {
        cell. Text = "0.00";
    }
 }

private void xrTableCell107_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

// Get values from the data source
decimal femaleBalance = Convert.ToDecimal(GetCurrentColumnValue("FemaleBalance") ?? 0);
decimal pol = Convert.ToDecimal(GetCurrentColumnValue("POL") ?? 0);
decimal total = Convert.ToDecimal(GetCurrentColumnValue("CummChicks1") ?? 0) + 
                    Convert.ToDecimal(GetCurrentColumnValue("CummCulls1") ?? 0) + 
                    Convert.ToDecimal(GetCurrentColumnValue("CummDeads1") ?? 0);

if (femaleBalance == 0)
{
    cell.Text = "0.00";
}
else if (pol > 0)
{
    // Calculate: (CummChicks1 + CummCulls1 + CummDeads1) / POL
    decimal result = total  / pol;
    cell.Text = result.ToString("N2");
}
else
{
    cell.Text = "0.00";
}

    // Add to cumulative totals for weighted average
    if (femaleBalance != 0 && pol > 0)
    {
        totalChicksSumReport += total;
        totalPolSumReport += pol;
        weightedCountReport++;
    }
}

