private void xrTableCell109_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

// Get values from the data source
decimal nestedEggs = Convert.ToDecimal(GetCurrentColumnValue("NestedEggs") ?? 0);
decimal floorEggs = Convert.ToDecimal(GetCurrentColumnValue("FloorEggs") ?? 0);
decimal hatchingEggs = Convert.ToDecimal(GetCurrentColumnValue("HatchingEggs") ?? 0);
decimal hatchingFloorG_B = Convert.ToDecimal(GetCurrentColumnValue("HatchingFloorG_B") ?? 0);
decimal hatchingFloorG_A = Convert.ToDecimal(GetCurrentColumnValue("HatchingFloorG_A") ?? 0);

// Calculate {@EggsProd}
decimal eggsProd = nestedEggs + floorEggs;

// Calculate {@HatchingFloorEggs}
decimal hatchingFloorEggs = hatchingFloorG_B + hatchingFloorG_A;

// Calculate {@HatchsEggs}
decimal hatchsEggs = hatchingEggs + hatchingFloorEggs;

if (eggsProd > 0)
{
    // Calculate: (HatchsEggs / EggsProd) * 100
    decimal result = (hatchsEggs / eggsProd) * 100.0m;
    cell.Text = result.ToString("N2");
}
else
{
    cell.Text = "0.00";
}

 // Add to cumulative totals (report-level)
    totalEggsProdReport += eggsProd;
    totalHatchingEggsReport += hatchingEggs;
    totalHatchingFloorG_BReport += hatchingFloorG_B;
    totalHatchingFloorG_AReport += hatchingFloorG_A;

}

