private void xrTableCell122_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
      XRTableCell cell = sender as XRTableCell;

    decimal totalHatchingFloorEggs = totalHatchingFloorG_BReport + totalHatchingFloorG_AReport;
    decimal totalHatchsEggs = totalHatchingEggsReport + totalHatchingFloorEggs;

    if (totalEggsProdReport > 0)
    {
        decimal result = (totalHatchsEggs / totalEggsProdReport) * 100.0m;
        cell.Text = result.ToString("N2") ;
    }
    else
    {
        cell.Text = "0.00";
    }
}

private void xrLabel11_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
  XRLabel label = sender as XRLabel;

// Get values from the data source
decimal weeklySettedEggs = Convert.ToDecimal(GetCurrentColumnValue("WeeklySettedEggs") ?? 0);
decimal weeklyChicks = Convert.ToDecimal(GetCurrentColumnValue("WeeklyChicks") ?? 0);
decimal weeklyCulls = Convert.ToDecimal(GetCurrentColumnValue("WeeklyCulls") ?? 0);
decimal weeklyDeads = Convert.ToDecimal(GetCurrentColumnValue("WeeklyDeads") ?? 0);

if (weeklySettedEggs > 0)
{
    // Calculate: (WeeklyChicks + WeeklyCulls + WeeklyDeads) / WeeklySettedEggs * 100
    decimal totalOutput = weeklyChicks + weeklyCulls + weeklyDeads;
    decimal result = (totalOutput / weeklySettedEggs) * 100.0m;
    label.Text = result.ToString("N2");
}
else
{
    label.Text = "0.00";
}
}

