private void xrTableCell103_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

// Get values from datasource
decimal nestedEggs   = Convert.ToDecimal(GetCurrentColumnValue("NestedEggs") ?? 0);
decimal floorEggs    = Convert.ToDecimal(GetCurrentColumnValue("FloorEggs") ?? 0);
decimal deformityEggs = Convert.ToDecimal(GetCurrentColumnValue("DeformityEggs") ?? 0);

// Calculations
decimal eggsProd = nestedEggs + floorEggs;
decimal deformeEggs = deformityEggs;

decimal result = 0;

if (eggsProd > 0)
{
    result = (deformeEggs / eggsProd) * 100.0m;
    cell.Text = result.ToString("N2");
}
else
{
    cell.Text = "0.00";
}

// Running totals (if needed)
sumEggsProdSiteReport += eggsProd;
sumDeformeEggsSiteReport += deformeEggs;
}


